# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for managing users, projects, tasks,
messages, performance analytics, and exportable reports.

The public surface (classes, enums and the :class:`TeamCollaborationManager`
methods) is exercised by ``test_solution.py``.  The design favours:

* A single shared re-entrant lock so every sub-system mutates state
  atomically and identifier generation is globally unique.
* Defensive copying on every read so callers can never mutate stored state.
* A clear, layered validation order that maps directly onto the documented
  exception hierarchy.

Standard library only; ASCII only.
"""

import copy
import csv
import enum
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import Dict, List, Optional


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails a validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(enum.Enum):
    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(enum.Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(enum.Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: Optional[datetime] = None


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole = UserRole.MEMBER
    created_at: Optional[datetime] = None


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Internal repository
# ---------------------------------------------------------------------------
class _Repository:
    """A thin keyed container that shares the manager's lock.

    The shared ``_lock`` attribute is what allows the manager and each of its
    sub-systems to coordinate every mutation through a single monitor.
    """

    def __init__(self, lock):
        self._lock = lock
        self._items = {}  # type: Dict[int, object]


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates users, projects, tasks, messages, performance and reports."""

    def __init__(self, now=None):
        # ``now`` is a callable returning the current ``datetime``.  Injecting
        # it keeps the whole system deterministic under test.
        self._clock = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        # Each sub-system shares the single lock instance.
        self.users = _Repository(self._lock)
        self.projects = _Repository(self._lock)
        self.tasks = _Repository(self._lock)
        self.messages = _Repository(self._lock)
        self.performance = _Repository(self._lock)
        self.reports = _Repository(self._lock)

        # Secondary indexes.
        self._tasks_by_assignee = {}  # type: Dict[int, set]
        self._ratings_by_ratee = {}  # type: Dict[int, List[int]]

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------
    def _now(self):
        return self._clock()

    def _next_id(self):
        self._id_counter += 1
        return self._id_counter

    def _require_user(self, user_id):
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    def _index_task(self, task):
        if task.assignee_id is not None:
            self._tasks_by_assignee.setdefault(task.assignee_id, set()).add(task.id)

    def _unindex_task(self, task):
        if task.assignee_id is not None:
            bucket = self._tasks_by_assignee.get(task.assignee_id)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    self._tasks_by_assignee.pop(task.assignee_id, None)

    def _tasks_for_assignee(self, user_id):
        ids = self._tasks_by_assignee.get(user_id, set())
        tasks = [self.tasks._items[tid] for tid in ids if tid in self.tasks._items]
        tasks.sort(key=lambda t: t.id)
        return tasks

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str) or email.strip() == "" or "@" not in email:
            raise ValidationError("a valid email is required")
        return email.strip()

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if not isinstance(username, str) or username.strip() == "":
                raise ValidationError("username is required")
            mail = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            uname = username.strip()
            for existing in self.users._items.values():
                if existing.username == uname:
                    raise DuplicateError("username already in use")
                if existing.email == mail:
                    raise DuplicateError("email already in use")
            user = User(
                id=self._next_id(),
                username=uname,
                email=mail,
                role=role,
                created_at=self._now(),
            )
            self.users._items[user.id] = user
            return copy.deepcopy(user)

    def get_user(self, user_id):
        with self._lock:
            return copy.deepcopy(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            return [
                copy.deepcopy(self.users._items[key])
                for key in sorted(self.users._items)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)
            if username is not None:
                if not isinstance(username, str) or username.strip() == "":
                    raise ValidationError("username is required")
                uname = username.strip()
                for other in self.users._items.values():
                    if other.id != user_id and other.username == uname:
                        raise DuplicateError("username already in use")
            if email is not None:
                mail = self._validate_email(email)
                for other in self.users._items.values():
                    if other.id != user_id and other.email == mail:
                        raise DuplicateError("email already in use")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None:
                user.username = username.strip()
            if email is not None:
                user.email = email.strip()
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id):
        with self._lock:
            self._require_user(user_id)
            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")
            for task in self.tasks._items.values():
                if task.assignee_id == user_id and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks assigned")
            self._tasks_by_assignee.pop(user_id, None)
            self._ratings_by_ratee.pop(user_id, None)
            self.users._items.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not isinstance(name, str) or name.strip() == "":
                raise ValidationError("project name is required")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")
            self._require_user(owner_id)
            project = Project(
                id=self._next_id(),
                name=name.strip(),
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
                created_at=self._now(),
            )
            self.projects._items[project.id] = project
            return copy.deepcopy(project)

    def get_project(self, project_id):
        with self._lock:
            return copy.deepcopy(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            return [
                copy.deepcopy(self.projects._items[key])
                for key in sorted(self.projects._items)
            ]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        with self._lock:
            project = self._require_project(project_id)
            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            if name is not None and (not isinstance(name, str) or name.strip() == ""):
                raise ValidationError("project name is required")
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            if name is not None:
                project.name = name.strip()
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return copy.deepcopy(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks_to_delete = [
                t for t in self.tasks._items.values()
                if t.project_id == project_id
            ]
            task_ids = {t.id for t in tasks_to_delete}
            messages_to_delete = [
                m for m in self.messages._items.values()
                if m.project_id == project_id
                or (m.task_id is not None and m.task_id in task_ids)
            ]
            for message in messages_to_delete:
                self.messages._items.pop(message.id, None)
            for task in tasks_to_delete:
                self._unindex_task(task)
                self.tasks._items.pop(task.id, None)
            self.projects._items.pop(project_id, None)

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or title.strip() == "":
                raise ValidationError("task title is required")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")
            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._now(),
            )
            self.tasks._items[task.id] = task
            self._index_task(task)
            return copy.deepcopy(task)

    def get_task(self, task_id):
        with self._lock:
            return copy.deepcopy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = [
                t for t in self.tasks._items.values()
                if t.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return [copy.deepcopy(t) for t in tasks]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._require_user(assignee_id)
            return [copy.deepcopy(t) for t in self._tasks_for_assignee(assignee_id)]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            if task.assignee_id != assignee_id:
                self._unindex_task(task)
                task.assignee_id = assignee_id
                self._index_task(task)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            if task.assignee_id != new_assignee_id:
                self._unindex_task(task)
                task.assignee_id = new_assignee_id
                self._index_task(task)
            return copy.deepcopy(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            self._unindex_task(task)
            task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                    attachments=None, parent_id=None):
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_specs = attachments or []
            if (not isinstance(body, str) or body.strip() == "") and not attachment_specs:
                raise ValidationError("message body or attachment is required")

            now = self._now()
            built_attachments = [
                self._build_attachment(filename, data, author_id, now)
                for filename, data in attachment_specs
            ]
            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body if isinstance(body, str) else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built_attachments,
                created_at=now,
                edited_at=None,
            )
            self.messages._items[message.id] = message
            return copy.deepcopy(message)

    @staticmethod
    def _build_attachment(filename, data, uploader_id, when):
        if not isinstance(filename, str) or filename.strip() == "":
            raise ValidationError("attachment filename is required")
        size = len(data) if data is not None else 0
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploader_id,
            uploaded_at=when,
        )

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if not isinstance(new_body, str) or new_body.strip() == "":
                raise ValidationError("message body is required")
            message.body = new_body
            message.edited_at = self._now()
            return copy.deepcopy(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may add attachments")
            attachment = self._build_attachment(
                filename, data, uploader_id, self._now()
            )
            message.attachments.append(attachment)
            return copy.deepcopy(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            messages = [
                m for m in self.messages._items.values()
                if m.project_id == project_id
            ]
            messages.sort(key=lambda m: m.id)
            return [copy.deepcopy(m) for m in messages]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            messages = [
                m for m in self.messages._items.values()
                if m.task_id == task_id
            ]
            messages.sort(key=lambda m: m.id)
            return [copy.deepcopy(m) for m in messages]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete a message")
            self.messages._items.pop(message_id, None)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            durations = [
                (t.completed_at - t.started_at).total_seconds()
                for t in self._tasks_for_assignee(user_id)
                if t.status == TaskStatus.COMPLETED
                and t.started_at is not None
                and t.completed_at is not None
            ]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool) \
                    or score < 1 or score > 5:
                raise ValidationError("score must be an integer in [1, 5]")
            if task_id is not None:
                self._require_task(task_id)
            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._items[rating.id] = rating
            self._ratings_by_ratee.setdefault(ratee_id, []).append(rating.id)
            return copy.deepcopy(rating)

    def _ratings_for(self, user_id):
        ids = self._ratings_by_ratee.get(user_id, [])
        ratings = [
            self.performance._items[rid]
            for rid in ids
            if rid in self.performance._items
        ]
        ratings.sort(key=lambda r: r.id)
        return ratings

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0
            avg_time = self.get_average_completion_time(user_id)
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    @staticmethod
    def _task_stats(tasks):
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        avg_time = sum(durations) / len(durations) if durations else None
        return {
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": avg_time,
        }

    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            now = self._now()
            tasks = [
                t for t in self.tasks._items.values()
                if t.project_id == project_id
            ]
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total_tasks": 0, "completed_tasks": 0},
                    )
                    bucket["total_tasks"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed_tasks"] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                scoped = [
                    t for t in self.tasks._items.values()
                    if t.project_id == project_id
                ]
            else:
                scoped = list(self.tasks._items.values())

            by_user = {}
            for task in scoped:
                if task.assignee_id is not None:
                    by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_user):
                stats = self._task_stats(by_user[user_id])
                ratings = self._ratings_for(user_id)
                rating_count = len(ratings)
                rating_average = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count else 0.0
                )
                user = self.users._items.get(user_id)
                rows.append({
                    "user_id": user_id,
                    "username": user.username if user is not None else "",
                    "total_tasks": stats["total_tasks"],
                    "completed_tasks": stats["completed_tasks"],
                    "completion_rate": stats["completion_rate"],
                    "average_completion_time": stats["average_completion_time"],
                    "rating_count": rating_count,
                    "rating_average": rating_average,
                })
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            stats = self._task_stats(tasks)
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count else 0.0
            )
            task_rows = [
                {
                    "id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "assignee_id": t.assignee_id,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": stats["total_tasks"],
                "completed_tasks": stats["completed_tasks"],
                "completion_rate": stats["completion_rate"],
                "average_completion_time": stats["average_completion_time"],
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report, report_format):
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a report dict")
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if report_format == ReportFormat.CSV:
                return self._report_to_csv(report)
            return self._report_to_pdf(report)

    def _report_to_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id", "username", "total_tasks", "completed_tasks",
                "completion_rate", "average_completion_time",
                "rating_count", "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([row.get(column, "") for column in header])
        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", report.get("project_id", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", 0)])
            for status, count in report.get("status_counts", {}).items():
                writer.writerow([status, count])
            writer.writerow(["completion_rate", report.get("completion_rate", 0.0)])
            writer.writerow(["overdue_tasks", report.get("overdue_tasks", 0)])
        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            header = [
                "task_id", "title", "status", "assignee_id",
                "deadline", "started_at", "completed_at",
            ]
            writer.writerow(header)
            for task in report.get("tasks", []):
                writer.writerow([
                    task.get("id"),
                    task.get("title"),
                    task.get("status"),
                    task.get("assignee_id"),
                    task.get("deadline"),
                    task.get("started_at"),
                    task.get("completed_at"),
                ])
        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                writer.writerow([key, value])
        return output.getvalue()

    def _report_to_pdf(self, report):
        return self._build_pdf(self._report_to_lines(report))

    @staticmethod
    def _report_to_lines(report):
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, (list, dict)):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines

    @staticmethod
    def _build_pdf(lines):
        """Build a minimal, structurally valid single-page PDF document."""
        commands = []
        y = 720
        for line in lines:
            safe = (
                str(line)
                .replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )
            commands.append("BT /F1 12 Tf 72 {0} Td ({1}) Tj ET".format(y, safe))
            y -= 16
            if y < 72:
                break
        content = "\n".join(commands).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
            b"<< /Length " + str(len(content)).encode("ascii")
            + b" >>\nstream\n" + content + b"\nendstream",
        ]

        pdf = b"%PDF-1.4\n"
        offsets = []
        for index, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += str(index).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

        xref_position = len(pdf)
        total = len(objects) + 1
        pdf += b"xref\n0 " + str(total).encode("ascii") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += (
            b"trailer\n<< /Size " + str(total).encode("ascii")
            + b" /Root 1 0 R >>\nstartxref\n"
            + str(xref_position).encode("ascii") + b"\n%%EOF"
        )
        return pdf
